# fix-about-signature-ts-error.ps1
# Fixes TS error: Type 'unknown' is not assignable to type 'ReactNode' (p.signatureUrl && ...)
$ErrorActionPreference = 'Stop'
Write-Host "Applying TypeScript build fix..." -ForegroundColor Cyan

Write-Host "Writing src\components\public\AboutSection.tsx"
$dir = Split-Path -Parent "src\components\public\AboutSection.tsx"
if ($dir -and !(Test-Path $dir)) { New-Item -ItemType Directory -Path $dir -Force | Out-Null }
$b64AboutSection = @"

"@
[System.IO.File]::WriteAllBytes("src\components\public\AboutSection.tsx", [System.Convert]::FromBase64String($b64AboutSection))

Write-Host "Done. 1 file updated." -ForegroundColor Green